#include <iostream>
#include <vector>
#include <string>
#include <algorithm>
#include <unordered_map>

using namespace std;
class Solution {
public:
    vector<vector<int>> findPairs(vector<int>& nums, int sum) {
        unordered_map<int, int> hashmap;
        vector<vector<int>> result;

        for (int i = 0; i < nums.size(); i++) {
            int currentSum = 0;
            for (int j = i; j < nums.size(); j++) {
                currentSum += nums[j];
                if (hashmap.find(currentSum) != hashmap.end()) {
                    result.push_back({nums.begin() + i, nums.begin() + j + 1});
                }
                hashmap[currentSum]++;
            }
        }
        return result;
    }
};

int main() {
    Solution solution;
    vector<int> nums = {1, 2, 3, 4, 5};
    int sum = 7;
    vector<vector<int>> result = solution.findPairs(nums, sum);
