// Solution
import java.util.*;
public class Solution {
public List<List<Integer>> findPairs(int[] nums, int sum) {
    Map<Integer, Integer> hashmap = new HashMap<>();
    List<List<Integer>> result = new ArrayList<>();

    for (int i = 0; i < nums.length; i++) {
        int currentSum = 0;
        for (int j = i; j < nums.length; j++) {
            currentSum += nums[j];
            if (hashmap.containsKey(currentSum)) {
                result.add(Arrays.asList(nums, i, nums[j + 1]));
            }
            hashmap.put(currentSum, hashmap.getOrDefault(currentSum, 0) + 1);
        }
    }
    return result;
}

public static void main(String[] args) {
    Solution solution = new Solution();
    int[] nums = {1, 2, 3, 4, 5};
    int sum = 7;
    List<List<Integer>> result = solution.findPairs(nums, sum);
    for (int i = 0; i < result.size(); i++) {
        for (int j = 0; j < result.get(i).size(); j++) {
            System.out.print(result.get(i).get(j) + ' ');
        }
        System.out.println();
    }
}}

