class Solution {
findPairs(nums, sum) {
    let hashmap = {};
    let result = [];

    for (let i = 0; i < nums.length; i++) {
        let currentSum = 0;
        for (let j = i; j < nums.length; j++) {
            currentSum += nums[j];
            if (currentSum in hashmap) {
                result.push(nums.slice(i, j + 1));
            }
            hashmap[currentSum] = (hashmap[currentSum] || 0) + 1;
        }
    }
    return result;
}

